// showAllPath rebuilds the list URL without the ids= filter so the "Show all"
// affordance (shown while a show-selected view is active) drops the selection
// filter and returns to the full list, preserving search/sort/order/filter/
// library/view. Uses data.Pagination.BaseURL (set by buildArtistListData),
// which is always the canonical /artists after the #1757 PR-3a cutover.
func showAllPath(data ArtistListData) string {
	v := url.Values{}
	if data.Search != "" {
		v.Set("search", data.Search)
	}
	if data.Sort != "" {
		v.Set("sort", data.Sort)
	}
	if data.Order != "" {
		v.Set("order", data.Order)
	}
	if data.Filter != "" {
		v.Set("filter", data.Filter)
	}
	if data.LibraryID != "" {
		v.Set("library_id", data.LibraryID)
	}
	if data.View != "" {
		v.Set("view", data.View)
	}
	for k, state := range data.Filters {
		switch state {
		case "include":
			v.Set("filter_"+k, "+y")
		case "exclude":
			v.Set("filter_"+k, "-y")
		}
	}
	base := data.Pagination.BaseURL
	if base == "" {
		base = "/artists"
	}
	enc := v.Encode()
	if enc == "" {
		return base
	}
	return base + "?" + enc
}

